const webhookBody = $('Webhook').first().json.body;
const dbRow = $input.first().json || {};
let req = webhookBody.requirements_json || dbRow.requirements_json || {};
if (typeof req === 'string') { try { req = JSON.parse(req); } catch(e) { req = {}; } }
let researchBrief = webhookBody.research_brief || dbRow.research_brief || {};
if (typeof researchBrief === 'string') { try { researchBrief = JSON.parse(researchBrief); } catch(e) { researchBrief = {}; } }
let storyline = webhookBody.storyline_json || dbRow.storyline_json || {};
if (typeof storyline === 'string') { try { storyline = JSON.parse(storyline); } catch(e) { storyline = {}; } }
const engagement_id = webhookBody.engagement_id || dbRow.id;
const client_name = webhookBody.client_name || dbRow.client_name || req.client_name || 'Client';
const deck_type = webhookBody.deck_type || dbRow.deck_type || req.deck_type || 'strategy';
const revision_notes = webhookBody.revision_notes || dbRow.revision_notes || '';
const slideSummary = storyline.slides ? storyline.slides.map(function(s, idx) {
  return 'Slide ' + (idx + 1) + ': ' + (s.slide_title || '') + ' - ' + (s.key_message || '');
}).join('\n') : '';
const keyQs = req.key_questions ? req.key_questions.join(' | ') : '';
const findings = researchBrief.key_findings ? researchBrief.key_findings.map(function(f) { return f.finding || f; }).join(' | ') : '';
const recs = researchBrief.strategic_recommendations ? researchBrief.strategic_recommendations.join(' | ') : '';
const risks = researchBrief.risks_and_considerations ? researchBrief.risks_and_considerations.join(' | ') : '';
let agentInput = 'You are the QA Reviewer for a consulting firm. Critically review this slide storyline against the original engagement brief and research findings.\n\n' +
  'ORIGINAL ENGAGEMENT BRIEF:\n' +
  'Client: ' + (req.client_name || client_name) + '\n' +
  'Deck Type: ' + (req.deck_type || deck_type) + '\n' +
  'Engagement Goal: ' + (req.engagement_goal || '') + '\n' +
  'Key Questions: ' + keyQs + '\n' +
  'Constraints: ' + (req.constraints || '') + '\n\n' +
  'RESEARCH BRIEF:\n' +
  'Market Context: ' + (researchBrief.market_context || '') + '\n' +
  'Key Findings: ' + findings + '\n' +
  'Strategic Recommendations: ' + recs + '\n' +
  'Risks: ' + risks + '\n\n' +
  'STORYLINE TO REVIEW:\n' +
  'Deck Title: ' + (storyline.deck_title || '') + '\n' +
  'Executive Summary: ' + (storyline.executive_summary || '') + '\n' +
  'Slides:\n' + slideSummary + '\n\n';
if (revision_notes) {
  agentInput += '\u26a0\ufe0f PREVIOUS QA FEEDBACK TO INCORPORATE: ' + revision_notes + '\n\n';
}
agentInput += 'Review against 5 criteria: (1) Answers all key questions, (2) MECE narrative, (3) Grounded in research, (4) Strong BLUF executive summary, (5) No logic gaps.\n\n' +
  'Output ONLY this JSON, no markdown:\n' +
  '{"qa_feedback": {"overall_score": 85, "answers_key_questions": true, "is_mece": true, "grounded_in_research": true, "strong_bluf": true, "logic_gaps": ["gap 1 if any"], "overall_feedback": "2-3 sentence summary", "recommended_action": "approve/revise", "revision_notes": "specific changes needed or empty string"}}';
return [{ json: { agent_input: agentInput, engagement_id: engagement_id, client_name: client_name, deck_type: deck_type, requirements: req, research_brief: researchBrief, storyline: storyline } }];

const raw = $input.first().json.output;
const prev = $('Code in JavaScript').first().json;
const cleaned = raw.replace(/```json\n?/g, '').replace(/```/g, '').trim();
var parsed = {};
try { parsed = JSON.parse(cleaned); } catch(e) { parsed = { qa_feedback: { overall_feedback: cleaned } }; }
const qa_feedback = parsed.qa_feedback || parsed;
return [{ json: { qa_feedback: qa_feedback, engagement_id: prev.engagement_id, client_name: prev.client_name, deck_type: prev.deck_type, requirements: prev.requirements, research_brief: prev.research_brief, storyline: prev.storyline } }];

